package com.atb.portfolio.utils

import androidx.compose.animation.core.*
import androidx.compose.foundation.Canvas
import androidx.compose.foundation.layout.Box
import androidx.compose.foundation.layout.size
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.geometry.Offset
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.Path
import androidx.compose.ui.graphics.drawscope.Stroke
import androidx.compose.ui.graphics.drawscope.withTransform
import androidx.compose.ui.layout.onGloballyPositioned
import androidx.compose.ui.layout.positionInRoot
import androidx.compose.ui.unit.dp
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch
import kotlin.math.atan2
import kotlin.math.cos
import kotlin.math.sin
import kotlin.math.PI

enum class PlushieMood {
    Watching,
    Waving
}

@Composable
fun PlushieComponent(mousePos: Offset, modifier: Modifier = Modifier) {
    var mood by remember { mutableStateOf(PlushieMood.Watching) }
    var globalPosition by remember { mutableStateOf(Offset.Zero) }

    val waveRotation = remember { Animatable(0f) }
    val handVisibility = remember { Animatable(0f) } // 0 to 1 for showing hand
    val excitementJump = remember { Animatable(0f) }

    val scope = rememberCoroutineScope()

    LaunchedEffect(Unit) {
        while (true) {
            delay((6000..12000).random().toLong())
            
            mood = PlushieMood.Waving
            
            // Start excitement jump
            scope.launch {
                repeat(2) {
                    excitementJump.animateTo(-15f, tween(200, easing = EaseOutBack))
                    excitementJump.animateTo(0f, tween(200, easing = EaseInBack))
                }
            }
            
            // Hand "emerges" and excitement starts
            handVisibility.animateTo(1f, tween(400, easing = FastOutSlowInEasing))
            
            repeat(5) {
                // Energetic waving at 45 degree angle
                waveRotation.animateTo(-50f, tween(180, easing = EaseInOutSine))
                waveRotation.animateTo(30f, tween(180, easing = EaseInOutSine))
            }
            waveRotation.animateTo(0f, tween(300))
            
            // Hand "hides" back
            handVisibility.animateTo(0f, tween(400, easing = FastOutSlowInEasing))
            
            mood = PlushieMood.Watching
        }
    }

    val infiniteTransition = rememberInfiniteTransition(label = "floating")
    val floatY by infiniteTransition.animateFloat(
        initialValue = -4f,
        targetValue = 4f,
        animationSpec = infiniteRepeatable(
            animation = tween(2500, easing = EaseInOutSine),
            repeatMode = RepeatMode.Reverse
        ),
        label = "float"
    )

    Box(
        modifier = modifier
            .onGloballyPositioned { globalPosition = it.positionInRoot() }
    ) {
        Canvas(
            modifier = Modifier.size(80.dp)
        ) {
            val bodyColor = Color(0xFF6FFFE9)
            val secondaryColor = Color(0xFF3DDC84)
            val eyeColor = Color(0xFF0B132B)
            
            // Body center with floating and jump
            val bodyCenter = Offset(
                size.width / 2, 
                size.height * 0.65f + floatY.dp.toPx() + excitementJump.value.dp.toPx()
            )

            // Body
            drawCircle(
                color = bodyColor,
                radius = size.width * 0.35f,
                center = bodyCenter
            )

            // Ears
            drawCircle(
                color = bodyColor,
                radius = size.width * 0.12f,
                center = bodyCenter + Offset(-size.width * 0.2f, -size.height * 0.28f)
            )
            drawCircle(
                color = bodyColor,
                radius = size.width * 0.12f,
                center = bodyCenter + Offset(size.width * 0.2f, -size.height * 0.28f)
            )
            
            // Eye positioning
            val leftEyeBase = bodyCenter + Offset(-size.width * 0.1f, -size.height * 0.05f)
            val rightEyeBase = bodyCenter + Offset(size.width * 0.1f, -size.height * 0.05f)

            if (mood == PlushieMood.Waving) {
                // Excited eyes: ^ ^
                val eyeWidth = 14f
                val eyeHeight = 10f
                val leftPath = Path().apply {
                    moveTo(leftEyeBase.x - eyeWidth / 2, leftEyeBase.y + eyeHeight / 4)
                    quadraticBezierTo(leftEyeBase.x, leftEyeBase.y - eyeHeight * 0.75f, leftEyeBase.x + eyeWidth / 2, leftEyeBase.y + eyeHeight / 4)
                }
                val rightPath = Path().apply {
                    moveTo(rightEyeBase.x - eyeWidth / 2, rightEyeBase.y + eyeHeight / 4)
                    quadraticBezierTo(rightEyeBase.x, rightEyeBase.y - eyeHeight * 0.75f, rightEyeBase.x + eyeWidth / 2, rightEyeBase.y + eyeHeight / 4)
                }
                drawPath(leftPath, eyeColor, style = Stroke(width = 3.5f))
                drawPath(rightPath, eyeColor, style = Stroke(width = 3.5f))
            } else {
                fun calculatePupilOffset(eyeBase: Offset): Offset {
                    val absEye = globalPosition + eyeBase
                    val dx = mousePos.x - absEye.x
                    val dy = mousePos.y - absEye.y
                    val angle = atan2(dy, dx)
                    val maxDist = 4.5f
                    return Offset(cos(angle) * maxDist, sin(angle) * maxDist)
                }

                val leftPupil = calculatePupilOffset(leftEyeBase)
                val rightPupil = calculatePupilOffset(rightEyeBase)

                // Eye Sockets
                drawCircle(Color.White.copy(alpha = 0.9f), radius = 7f, center = leftEyeBase)
                drawCircle(Color.White.copy(alpha = 0.9f), radius = 7f, center = rightEyeBase)

                // Pupils
                drawCircle(eyeColor, radius = 4f, center = leftEyeBase + leftPupil)
                drawCircle(eyeColor, radius = 4f, center = rightEyeBase + rightPupil)
            }
            
            // Blushed cheeks
            drawCircle(Color(0xFFFFB7B2).copy(alpha = 0.6f), radius = 5f, center = bodyCenter + Offset(-size.width * 0.18f, size.height * 0.05f))
            drawCircle(Color(0xFFFFB7B2).copy(alpha = 0.6f), radius = 5f, center = bodyCenter + Offset(size.width * 0.18f, size.height * 0.05f))

            // Mouth
            val mouthPath = Path().apply {
                if (mood == PlushieMood.Waving) {
                    moveTo(bodyCenter.x - 7.dp.toPx(), bodyCenter.y + 6.dp.toPx())
                    quadraticBezierTo(bodyCenter.x, bodyCenter.y + 15.dp.toPx(), bodyCenter.x + 7.dp.toPx(), bodyCenter.y + 6.dp.toPx())
                } else {
                    moveTo(bodyCenter.x - 4.dp.toPx(), bodyCenter.y + 6.dp.toPx())
                    quadraticBezierTo(bodyCenter.x, bodyCenter.y + 10.dp.toPx(), bodyCenter.x + 4.dp.toPx(), bodyCenter.y + 6.dp.toPx())
                }
            }
            drawPath(mouthPath, eyeColor, style = Stroke(width = 2.5f))

            // The Waving Hand (Raised 45 degrees, energetical wave)
            val shoulderPos = bodyCenter + Offset(size.width * 0.25f, -size.height * 0.05f)
            
            withTransform({
                // Hand emerges by scaling up
                scale(handVisibility.value, handVisibility.value, pivot = shoulderPos)
                // Base rotation to raise the hand above at ~45 degrees, then add the wave
                rotate(-45f + waveRotation.value, pivot = shoulderPos)
            }) {
                // Stubby Arm
                val armLength = 16f
                val palmPos = shoulderPos + Offset(armLength, 0f)
                
                drawLine(
                    color = bodyColor,
                    start = shoulderPos,
                    end = palmPos,
                    strokeWidth = 16f
                )

                // Hand Palm
                drawCircle(
                    color = bodyColor,
                    radius = 12f,
                    center = palmPos
                )
                
                // Detailed Fingers
                for (i in 0 until 4) {
                    val angle = (i * 28 - 42).toDouble() * (PI / 180)
                    val fingerStart = palmPos + Offset((cos(angle) * 8f).toFloat(), (sin(angle) * 18f).toFloat())
                    val fingerEnd = palmPos + Offset((cos(angle) * 18f).toFloat(), (sin(angle) * 18f).toFloat())
                    
                    drawLine(
                        color = bodyColor,
                        start = fingerStart,
                        end = fingerEnd,
                        strokeWidth = 6f
                    )
                }
                
                // Outline
                drawCircle(
                    color = secondaryColor.copy(alpha = 0.4f),
                    radius = 12f,
                    center = palmPos,
                    style = Stroke(width = 1.2f)
                )
            }
        }
    }
}
