@Composable
fun AboutPage() {
    var mousePos by remember { mutableStateOf(Offset.Zero) }

    BoxWithConstraints(
        modifier = Modifier
            .fillMaxWidth()
            .wrapContentHeight()
            .pointerInput(Unit) {
                awaitPointerEventScope {
                    while (true) {
                        val event = awaitPointerEvent()
                        mousePos = event.changes.first().position
                    }
                }
            }
    ) {
        val deviceType = remember { getDeviceType() }
        val isPhone = deviceType == DeviceType.Phone

        val horizontalPadding = if (isPhone) 20.dp else 100.dp
        
        val columnModifier = if (isPhone) {
            Modifier.fillMaxWidth().wrapContentHeight()
        } else {
            Modifier.fillMaxSize()
        }

        Column(
            modifier = columnModifier
                .padding(top = 48.dp, bottom = 48.dp, start = horizontalPadding, end = horizontalPadding)
                .scrollReveal(),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.spacedBy(32.dp)
        ) {
            if (isPhone) {
                // Only phones get stacked layout
                ProfileCard(mousePos)
                AboutMeContent(isPhone = true)
            } else {
                // Everything else = Desktop layout (zoom safe)
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(32.dp),
                    verticalAlignment = Alignment.Top
                ) {
                    Box(modifier = Modifier.width(320.dp)) {
                        ProfileCard(mousePos)
                    }
                    Box(modifier = Modifier.weight(1f)) {
                        AboutMeContent(isPhone = false)
                    }
                }
            }
        }
    }
}

