@OptIn(ExperimentalFoundationApi::class)
@Composable
fun TechChip(
    text: String, modifier: Modifier = Modifier
) {
    val interactionSource = remember { MutableInteractionSource() }

    val isHovered by interactionSource.collectIsHoveredAsState()
    val isPressed by interactionSource.collectIsPressedAsState()

    val borderColor by animateColorAsState(
        targetValue = when {
            isPressed -> Color(0xFF80DEEA)
            isHovered -> Color(0xFF4DD0E1)
            else -> Color(0xFF4DD0E1).copy(alpha = 0.5f)
        }, label = "borderColor"
    )

    val backgroundColor by animateColorAsState(
        targetValue = when {
            isPressed -> Color(0xFF4DD0E1).copy(alpha = 0.15f)
            isHovered -> Color(0xFF4DD0E1).copy(alpha = 0.10f)
            else -> Color.Transparent
        }, label = "backgroundColor"
    )

    val scale by animateFloatAsState(
        targetValue = if (isHovered) 1.04f else 1f, label = "scale"
    )

    Surface(
        modifier = modifier
            .graphicsLayer {
                scaleX = scale
                scaleY = scale
            }
            .hoverable(interactionSource)
            .clickable(
                interactionSource = interactionSource, indication = null // keeps it clean
            ) {},
        shape = RoundedCornerShape(50),
        color = backgroundColor,
        border = BorderStroke(1.dp, borderColor),
        tonalElevation = if (isHovered) 2.dp else 0.dp
    ) {
        Text(
            text = text, modifier = Modifier.padding(
                horizontal = 14.dp, vertical = 8.dp
            ), style = MaterialTheme.typography.labelMedium, color = Color(0xFFB2EBF2)
        )
    }
}
